// Parse la réponse IA et extrait le JSON
const aiResponse = $input.first().json.message?.content || $input.first().json.text || '';

// Essayer d'extraire le JSON de la réponse
let result;
try {
  // Chercher un objet ou tableau JSON dans la réponse
  const jsonMatch = aiResponse.match(/[\[\{][\s\S]*[\]\}]/);
  if (jsonMatch) {
    result = JSON.parse(jsonMatch[0]);
  } else {
    result = JSON.parse(aiResponse);
  }
} catch (e) {
  // En cas d'erreur, retourner un objet d'erreur
  result = { error: 'Impossible de parser la réponse IA', raw: aiResponse };
}

return [{ json: result }];

// Log l'événement CRM
const event = $input.first().json;

console.log('CRM Event tracked:', event.data.eventType);
console.log('Event data:', JSON.stringify(event.data, null, 2));

// On pourrait ici:
// - Envoyer à un système d'analytics
// - Stocker dans une base de données
// - Déclencher des automatisations

return [{ json: { success: true, eventType: event.data.eventType, timestamp: new Date().toISOString() } }];
